/**
 * Pre-built episode scripts for "La Isla Mágica"
 * Structure: Episode → Blocks (Scenes) → Clips (10s each)
 * Target: ~90 clips per episode = 15 minutes
 * Characters: @Tomas, @Lia, @Noah, @Coco  |  Location: @Isla
 */

import { SceneBlueprint, ClipBlueprint } from "../components/AIDirectorPanel";

/* ─── helpers ─────────────────────────────────────────── */
function cam(
  style = "auto", pan = "none", tilt = "none", zoom = "none",
  speed = "normal", timeOfDay = "day"
): ClipBlueprint["cameraSettings"] {
  return { style, pan, tilt, zoom, roll: "none", speed, timeOfDay, motionCurve: "ease-in-out" };
}
function clip(n: number, title: string, prompt: string, camSettings?: Partial<ClipBlueprint["cameraSettings"]>): ClipBlueprint {
  return { clipNumber: n, title, prompt, cameraSettings: { ...cam(), ...camSettings }, duration: 10, generate_audio: false, consistencyExplanation: "" };
}

